var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"힐데 소대장님, 어떻게 된 거죠?","JPN":"ヒルデ小隊長、どうなっているんですか？","ENG":"Commander Hilde, what’s going on?","TWN":"希爾德小隊長，這是怎麼回事？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"오비탈 베이스가 강제로 끌려가고 있다.","JPN":"オービタルベースが強制的に引っ張られている。","ENG":"The Orbital Base is being dragged to another location.","TWN":"軌道基地正強行被拖走，"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"도착지는 아마도 그림자 전당으로 추정된다더군.","JPN":"到着地はおそらく影の殿堂とみられるそうだ。","ENG":"The destination is predicted to be the Shadow Palaces.","TWN":"推測目的地是暗影殿堂。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그림자 전당? 한탕만 쫓는 멍청이들의 무덤이라는 그 고위험 좌표요?","JPN":"影の殿堂？　一発逆転ばかりを狙うおばかさんたちの墓っていう、あの高危険度の座標ですか？","ENG":"The Shadow Palaces? You mean the highly dangerous coordinates known as Fools’ Folly?","TWN":"暗影殿堂？是有窮追不捨傻瓜墳場之稱的高危險座標嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"알고 있나?","JPN":"知っているのか？","ENG":"Do you know about it?","TWN":"你知道那個地方？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"모를 리가 없죠. 관리국에서 공식적으로 발표한 좌표인데요.","JPN":"知らないわけがないでしょう。管理局で公式的に発表した座標ですし。","ENG":"How could I not? Those are coordinates officially published by the Administration.","TWN":"怎麼可能不知道，那不是管理局正式公佈的座標嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그리고 그림자들과는 처음 입사했을 때부터 안 좋은 인연이기도 했고요.","JPN":"それに、シャドウとは初めて入社したときからの腐れ縁でもあります。","ENG":"Also, I had a few bad run-ins with Shadows ever since I first joined.","TWN":"而且從我剛進公司時，就和暗影有過不好的經驗。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼 더 설명할 필요 없겠군. 이수연 부사장이 우릴 뒤따라올 때까지 오비탈 베이스를 사수한다.","JPN":"では説明する必要もないな。カナミ副社長が我々に追いつくまでオービタルベースを死守する。","ENG":"Then I won’t have to provide further explanation. We must secure the Orbital Base until Vice President Lee Sooyeon arrives.","TWN":"那無須再多做解釋，在李秀妍副總抵達前，務必守住軌道基地。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"힐데 소대장님이 계시니까 정면은 물론 걱정이 없겠지만……","JPN":"ヒルデ小隊長がいらっしゃるから正面は心配ないとしても……","ENG":"Since you’re here, I’m not too worried about the front...","TWN":"前面有希爾德小隊長在應該是不需要擔心……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"여긴 그림자들이 우글거리는 곳이라고 들었어요.","JPN":"ここはシャドウがうようよいる場所だそうです。","ENG":"However, I heard that this place is crawling with Shadows.","TWN":"但我聽說這裡是暗影聚集的地方，"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저희들만으로 오비탈 베이스를 방어하기는 어려울 걸요.","JPN":"私たちだけでオービタルベースを守るのは難しいと思いますよ。","ENG":"It may be difficult to defend the Orbital Base by ourselves.","TWN":"光憑我們幾個恐怕很難守住軌道基地。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그건 곤란하군.","JPN":"……それは困るな。","ENG":"...That’s bad news.","TWN":"……傷腦筋呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"전투가 길어지면 도플갱어 신드롬도 악화될 가능성이 커.","JPN":"戦闘が長引けばドッペルゲンガーシンドロームも悪化する可能性が高い。","ENG":"The longer the battle drags on, the higher the risk of Doppelganger Syndrome getting worse.","TWN":"作戰時間拉得越長，二重身症候群增加的可能性也越大。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 도플갱어 신드롬 말인데, 그림자와는 다른 건가요?","JPN":"そのドッペルゲンガーシンドロームですが、シャドウとは違うんですか？","ENG":"This Doppelganger Syndrome you just mentioned, is it different from the Shadows?","TWN":"那個所謂的二重身症候群，和暗影是不同的嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 이 공간의 침식파가 내부에서 활동하는 개체의 에너지에 반응해 대상의 복제를 만들어 내는 거다.","JPN":"そうだ。この空間の侵食波が内部で活動する個体のエネルギーに反応して、対象のクローンを作り出すんだ。","ENG":"That’s correct. The Corruption Ray permeating throughout this space will respond to an active entity’s energy and create a clone.","TWN":"嗯，這個空間的侵蝕波會對在裡面的個體能量產生反應，再製造出該個體的複製品。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"카운터가 변이하는 그림자와 비교하면 일종의 대량 생산품인 셈이지.","JPN":"カウンターが変異するシャドウと比べると、一種の大量生産品というわけだ。","ENG":"If you compare it to a Shadow, which is a morphed Counter, it’s the equivalent of a mass produced item.","TWN":"暗影是變種的制裁者，二重身則是一種可以大量生產的複製品。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"전투로 방출되는 에너지가 늘어나거나, 혹은 다른 이유로나 악화되면 끝도 없이 쏟아져 나오게 되지.","JPN":"戦闘で放出されるエネルギーが増大するか、他の理由ででも、悪化すれば際限なく溢れ出るようになる。","ENG":"If the energy released during a battle is increased, or gets corrupted for some other reason, they’ll keep pouring in an endless tide.","TWN":"當能量因為戰鬥或是其他理由而增加時，複製品就會不斷地湧現。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};